INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('a12ddf66-fd38-4219-acf5-7859c01270b4', 'RCW_Q2_2025_FLY_001', 'Điền từ vào đoạn văn', '{"title": "", "imageUrl": "questions/images/1774396368141_c4fe2a02_q2_rw_p3_1.png", "viewMode": "WITH_WORD_BANK", "wordBank": [{"word": "cake", "imageUrl": "", "isExample": true}, {"word": "call", "imageUrl": ""}, {"word": "early", "imageUrl": ""}, {"word": "surprise", "imageUrl": ""}, {"word": "caught", "imageUrl": ""}, {"word": "address", "imageUrl": ""}, {"word": "saw", "imageUrl": ""}, {"word": "week", "imageUrl": ""}, {"word": "name", "imageUrl": ""}, {"word": "interesting", "imageUrl": ""}], "paragraph": "Last Saturday I went shopping with my mum and my sister. We were very tired after the shopping, so mum took us to a café for a drink and a piece of {0}.\n\nJust before we left the café, I {1} a handbag on the floor under my chair. I showed it to my mum. She said, \"You should give it to the man who works in the café.\" So, I went to the waiter and gave him the handbag. He took it and asked for my {2} and telephone number.\n\nA {3} later the telephone rang. My mum called to me, \"Daisy, there''s a woman on the phone for you. Her name''s Mrs White.\" I was {4} because I didn''t know anyone called Mrs White. I took the phone and spoke to the woman. The handbag I found in the café was Mrs White''s! She was very pleased to have her handbag back and asked for my {5}. Two days later I got a thank you letter from Mrs White with some money!", "exampleAnswer": ["cake"]}', '{"answers": ["cake", "saw", "name", "week", "surprise", "address"], "example": ["cake"], "caseSensitive": false}', 'WORD_FILL_PARAGRAPH', 'medium', null, 1.00, null, null, '');
INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('2e2a9a0f-042c-437e-86c4-bf9cdc17dbbe', 'RCW_Q2_2025_FLY_003', 'Điền từ vào đoạn văn - Có lựa chọn', '{"title": "Firefighters", "viewMode": "WITH_OPTIONS", "wordBank": [{"options": ["all", "each", "any"], "isExample": true}, {"options": ["help", "helps", "helping"]}, {"options": ["need", "can", "should"]}, {"options": ["quick", "quicker", "quickly"]}, {"options": ["these", "this", "those"]}, {"options": ["who", "how", "what"]}, {"options": ["no-one", "someone", "everyone"]}, {"options": ["into", "onto", "over"]}, {"options": ["is", "are", "be"]}, {"options": ["a", "an", "the"]}, {"options": ["so", "because", "but"]}], "paragraph": "A firefighter''s job is very important and {0} day is always different. Often firefighters {1} people who have a fire in their house. Other times, the fire is in a factory or an office. A fire {2} grow very fast and so it is important that the team of firefighters work very {3}. In the past {4} job was only for men but of course now there are women {5} work at fire stations. When {6} calls a fire station, a team of about five firefighters get {7} a fire engine and drive to where the fire {8}. The driver of the fire engine must drive very fast but carefully. To be a firefighter you need to be brave because it can be {9} very dangerous job. You can''t be afraid of climbing and you need to be strong {10} you will sometimes carry heavy things."}', '{"answers": ["each", "help", "can", "quickly", "this", "who", "someone", "into", "is", "a", "because"], "caseSensitive": false}', 'WORD_FILL_PARAGRAPH', 'medium', null, 1.00, null, null, '');
INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('40d5c8b6-d1eb-4614-b4bb-b0b1f0135ea6', 'LWW_Q2_2025_FLY_001', 'Điền vào chỗ trống', '{"hints": [], "title": "My first day at school", "content": "My name''s Betty Stewart and I''m an English teacher. I was twenty-two years old when I got my first teaching job. I remember my first day very well!\n\nThe day didn''t start well. I got up early and got dressed. Then I dropped my cereal all over my new skirt. I quickly put on clean clothes. I picked up my bag and went to the bus stop. I saw a lot of people waiting for the bus. I asked a woman, \"Why are there so many people?\" She said \"There''s a lot of traffic in the city centre and all the buses are late.\" So, I decided to walk to school.\n\nI only had half an hour before my first lesson. I walked very quickly. After some time I could see the school at the end of the road. I felt very happy. Suddenly it started to rain. I ran fast but I was very wet when I arrived at school. When I got to my classroom I was five minutes late and I looked wet and horrible. At first, my new students looked surprised when they saw me. Then they all smiled and said, \"Good morning Miss Stewart!\" I smiled back and said \"Good morning class!\" After that, the day got much better.", "imageUrl": "", "question": "Betty''s job is a {0}.", "showHints": false}', '{"answers": ["teacher"], "caseSensitive": false}', 'FILL_IN_BLANK', 'medium', null, 1.00, null, null, '');
INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('2d9408a2-682a-4d43-9889-03cbee9ccd3b', 'LWW_Q2_2025_FLY_002', 'Điền vào chỗ trống', '{"hints": [], "title": "My first day at school", "content": "My name''s Betty Stewart and I''m an English teacher. I was twenty-two years old when I got my first teaching job. I remember my first day very well!\n\nThe day didn''t start well. I got up early and got dressed. Then I dropped my cereal all over my new skirt. I quickly put on clean clothes. I picked up my bag and went to the bus stop. I saw a lot of people waiting for the bus. I asked a woman, \"Why are there so many people?\" She said \"There''s a lot of traffic in the city centre and all the buses are late.\" So, I decided to walk to school.\n\nI only had half an hour before my first lesson. I walked very quickly. After some time I could see the school at the end of the road. I felt very happy. Suddenly it started to rain. I ran fast but I was very wet when I arrived at school. When I got to my classroom I was five minutes late and I looked wet and horrible. At first, my new students looked surprised when they saw me. Then they all smiled and said, \"Good morning Miss Stewart!\" I smiled back and said \"Good morning class!\" After that, the day got much better.", "imageUrl": "", "question": "She started teaching when she was {0} old.", "showHints": false}', '{"answers": ["tweny-two years"], "caseSensitive": false}', 'FILL_IN_BLANK', 'medium', null, 1.00, null, null, '');
