INSERT INTO public.questions (id, content, correct_answer, points, question_type, explanation, exam_id, part_id, part_no, question_number, group_id, question_bank_id, question_skill_type, is_example, suggested_answers) VALUES ('5e5ae06e-7597-4430-8ca1-28765ceb889b', '{"title": "", "imageUrl": "questions/images/1774396368141_c4fe2a02_q2_rw_p3_1.png", "viewMode": "WITH_WORD_BANK", "wordBank": [{"word": "cake", "imageUrl": "", "isExample": true}, {"word": "call", "imageUrl": ""}, {"word": "early", "imageUrl": ""}, {"word": "surprise", "imageUrl": ""}, {"word": "caught", "imageUrl": ""}, {"word": "address", "imageUrl": ""}, {"word": "saw", "imageUrl": ""}, {"word": "week", "imageUrl": ""}, {"word": "name", "imageUrl": ""}, {"word": "interesting", "imageUrl": ""}], "paragraph": "Last Saturday I went shopping with my mum and my sister. We were very tired after the shopping, so mum took us to a café for a drink and a piece of {0}.\n\nJust before we left the café, I {1} a handbag on the floor under my chair. I showed it to my mum. She said, \"You should give it to the man who works in the café.\" So, I went to the waiter and gave him the handbag. He took it and asked for my {2} and telephone number.\n\nA {3} later the telephone rang. My mum called to me, \"Daisy, there''s a woman on the phone for you. Her name''s Mrs White.\" I was {4} because I didn''t know anyone called Mrs White. I took the phone and spoke to the woman. The handbag I found in the café was Mrs White''s! She was very pleased to have her handbag back and asked for my {5}. Two days later I got a thank you letter from Mrs White with some money!", "exampleAnswer": ["cake"]}', '{"answers": ["cake", "saw", "name", "week", "surprise", "address"], "example": ["cake"], "caseSensitive": false}', 1.00, 'WORD_FILL_PARAGRAPH', '', 'a0676e0b-eece-46cf-a80a-872952488fcc', '8', 8, 38, null, 'a12ddf66-fd38-4219-acf5-7859c01270b4', 'READING', false, null);
INSERT INTO public.questions (id, content, correct_answer, points, question_type, explanation, exam_id, part_id, part_no, question_number, group_id, question_bank_id, question_skill_type, is_example, suggested_answers) VALUES ('8e3260f3-0092-43a5-9c8e-65af46d22390', '{"title": "Firefighters", "viewMode": "WITH_OPTIONS", "wordBank": [{"options": ["all", "each", "any"], "isExample": true}, {"options": ["help", "helps", "helping"]}, {"options": ["need", "can", "should"]}, {"options": ["quick", "quicker", "quickly"]}, {"options": ["these", "this", "those"]}, {"options": ["who", "how", "what"]}, {"options": ["no-one", "someone", "everyone"]}, {"options": ["into", "onto", "over"]}, {"options": ["is", "are", "be"]}, {"options": ["a", "an", "the"]}, {"options": ["so", "because", "but"]}], "paragraph": "A firefighter''s job is very important and {0} day is always different. Often firefighters {1} people who have a fire in their house. Other times, the fire is in a factory or an office. A fire {2} grow very fast and so it is important that the team of firefighters work very {3}. In the past {4} job was only for men but of course now there are women {5} work at fire stations. When {6} calls a fire station, a team of about five firefighters get {7} a fire engine and drive to where the fire {8}. The driver of the fire engine must drive very fast but carefully. To be a firefighter you need to be brave because it can be {9} very dangerous job. You can''t be afraid of climbing and you need to be strong {10} you will sometimes carry heavy things."}', '{"answers": ["each", "help", "can", "quickly", "this", "who", "someone", "into", "is", "a", "because"], "caseSensitive": false}', 1.00, 'WORD_FILL_PARAGRAPH', '', 'a0676e0b-eece-46cf-a80a-872952488fcc', '9', 9, 40, null, '2e2a9a0f-042c-437e-86c4-bf9cdc17dbbe', 'READING', false, null);
INSERT INTO public.questions (id, content, correct_answer, points, question_type, explanation, exam_id, part_id, part_no, question_number, group_id, question_bank_id, question_skill_type, is_example, suggested_answers) VALUES ('ce48d112-6fca-4ece-9f96-fb41cfd09f0b', '{"hints": [], "title": "My first day at school", "content": "My name''s Betty Stewart and I''m an English teacher. I was twenty-two years old when I got my first teaching job. I remember my first day very well!\n\nThe day didn''t start well. I got up early and got dressed. Then I dropped my cereal all over my new skirt. I quickly put on clean clothes. I picked up my bag and went to the bus stop. I saw a lot of people waiting for the bus. I asked a woman, \"Why are there so many people?\" She said \"There''s a lot of traffic in the city centre and all the buses are late.\" So, I decided to walk to school.\n\nI only had half an hour before my first lesson. I walked very quickly. After some time I could see the school at the end of the road. I felt very happy. Suddenly it started to rain. I ran fast but I was very wet when I arrived at school. When I got to my classroom I was five minutes late and I looked wet and horrible. At first, my new students looked surprised when they saw me. Then they all smiled and said, \"Good morning Miss Stewart!\" I smiled back and said \"Good morning class!\" After that, the day got much better.", "imageUrl": "", "question": "Betty''s job is a {0}.", "showHints": false}', '{"answers": ["teacher"], "caseSensitive": false}', 1.00, 'FILL_IN_BLANK', '', 'a0676e0b-eece-46cf-a80a-872952488fcc', '10', 10, 41, '60fe649f-a0a2-4c73-840a-64d297a4a368', '40d5c8b6-d1eb-4614-b4bb-b0b1f0135ea6', 'READING', true, null);
