INSERT INTO public.questions (id, content, correct_answer, points, question_type, explanation, exam_id, part_id, part_no, question_number, group_id, question_bank_id, question_skill_type, is_example, suggested_answers) VALUES ('14f9f081-c159-47b6-a3f9-968f83f84e6e', '{"title": "", "viewMode": "DEFAULT", "wordBank": [], "paragraph": "Tuesday 23rd July\n\nDear Grandma,\n\nWe''re {0} a good time on holiday.\nOur hotel is great. I''ve got a big room and I can see the sea {1} my window! Yesterday we visited a castle. I {2} lots of photos with my camera. The castle was very {3} and we heard lots of interesting stories {4} the kings and queens who lived there. It''s hot and sunny today so we''re {5} to go to the beach this afternoon.\n\nSee you soon.\n\nLots of love,\n\nSarah."}', '{"answers": ["having", "from", "took", "old", "about", "going"], "caseSensitive": false}', 1.00, 'WORD_FILL_PARAGRAPH', '', 'a0676e0b-eece-46cf-a80a-872952488fcc', '11', 11, 50, null, '59571705-bbbf-453b-a0f6-3fc7e12d7597', 'READING', false, null);
